import os, base64

def reconstruct():
    os.makedirs("extension/icons", exist_ok=True)
    with open("extension/manifest.json", "w") as f: f.write('{\n  "manifest_version": 3,\n  "name": "SRT Fact-Check AI",\n  "version": "1.0",\n  "description": "AI-powered fact-checking assistant for SRT platform",\n  "icons": {\n    "16": "icons/icon16.png",\n    "48": "icons/icon48.png",\n    "128": "icons/icon128.png"\n  },\n  "permissions": [\n    "activeTab",\n    "scripting",\n    "storage"\n  ],\n  "host_permissions": [\n    "https://*.facebook.com/*",\n    "https://*.instagram.com/*",\n    "https://*.threads.net/*",\n    "https://factcheckai-api.onrender.com/*"\n  ],\n  "action": {\n    "default_popup": "popup.html",\n    "default_icon": {\n      "16": "icons/icon16.png",\n      "48": "icons/icon48.png",\n      "128": "icons/icon128.png"\n    }\n  },\n  "content_scripts": [\n    {\n      "matches": [\n        "https://*.facebook.com/*",\n        "https://*.instagram.com/*",\n        "https://*.threads.net/*"\n      ],\n      "js": [\n        "content.js"\n      ]\n    }\n  ],\n  "background": {\n    "service_worker": "background.js"\n  }\n}')
    with open("extension/popup.js", "w") as f: f.write('// Configure your backend URL here (e.g., https://your-app.onrender.com/factcheck)\nconst BACKEND_URL = \'https://factcheckai-api.onrender.com/factcheck\';\n\ndocument.addEventListener(\'DOMContentLoaded\', async () => {\n    const detectedTextDiv = document.getElementById(\'detected-text\');\n    const checkBtn = document.getElementById(\'check-btn\');\n    const loading = document.getElementById(\'loading\');\n    const resultDiv = document.getElementById(\'result\');\n\n    let extractedText = "";\n\n    // 1. Ask content script for text\n    try {\n        const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });\n        if (tab) {\n            chrome.tabs.sendMessage(tab.id, { action: "extractText" }, (response) => {\n                if (response && response.text) {\n                    extractedText = response.text;\n                    detectedTextDiv.innerText = extractedText;\n                    checkBtn.disabled = false;\n                } else {\n                    detectedTextDiv.innerText = "No claim detected on this page.";\n                }\n            });\n        }\n    } catch (err) {\n        detectedTextDiv.innerText = "Error communicating with tab: " + err.message;\n    }\n\n    // 2. Click handler for check button\n    checkBtn.addEventListener(\'click\', async () => {\n        checkBtn.style.display = \'none\';\n        loading.style.display = \'block\';\n        resultDiv.style.display = \'none\';\n\n        try {\n            // Call FastAPI (assuming local for now)\n            const response = await fetch(BACKEND_URL, {\n                method: \'POST\',\n                headers: {\n                    \'Content-Type\': \'application/json\'\n                },\n                body: JSON.stringify({ text: extractedText })\n            });\n\n            if (!response.ok) {\n                throw new Error(\'Backend error: \' + response.statusText);\n            }\n\n            const data = await response.json();\n\n            // Basic formatting of Markdown result\n            resultDiv.innerHTML = formatMarkdown(data.verdict_md);\n            resultDiv.style.display = \'block\';\n        } catch (err) {\n            resultDiv.innerText = "Error: " + err.message;\n            resultDiv.style.display = \'block\';\n            checkBtn.style.display = \'block\';\n        } finally {\n            loading.style.display = \'none\';\n        }\n    });\n});\n\n// Simple markdown subset formatter\nfunction formatMarkdown(md) {\n    return md\n        .replace(/\\*\\*(.*?)\\*\\*/g, \'<strong>$1</strong>\')\n        .replace(/\\*(.*?)\\*/g, \'<em>$1</em>\')\n        .replace(/\\n\\n/g, \'<br><br>\')\n        .replace(/\\n/g, \'<br>\')\n        .replace(/- (.*?)/g, \'• $1\');\n}\n')
    with open("extension/popup.html", "w") as f: f.write('<!DOCTYPE html>\n<html>\n<head>\n  <title>SRT Fact-Check AI</title>\n  <style>\n    body {\n      width: 350px;\n      padding: 15px;\n      font-family: \'Segoe UI\', Tahoma, Geneva, Verdana, sans-serif;\n      margin: 0;\n      background: #f4f7f6;\n    }\n    .header {\n      display: flex;\n      align-items: center;\n      margin-bottom: 15px;\n      border-bottom: 1px solid #ddd;\n      padding-bottom: 10px;\n    }\n    .header h2 {\n      margin: 0;\n      font-size: 18px;\n      color: #2c3e50;\n    }\n    .content-box {\n      background: white;\n      padding: 10px;\n      border-radius: 8px;\n      box-shadow: 0 2px 5px rgba(0,0,0,0.1);\n      margin-bottom: 15px;\n      min-height: 50px;\n      max-height: 150px;\n      overflow-y: auto;\n      font-size: 13px;\n    }\n    #result {\n      background: white;\n      padding: 10px;\n      border-radius: 8px;\n      box-shadow: 0 2px 5px rgba(0,0,0,0.1);\n      font-size: 13px;\n      line-height: 1.4;\n      display: none;\n    }\n    button {\n      width: 100%;\n      background: #3498db;\n      color: white;\n      border: none;\n      padding: 10px;\n      border-radius: 5px;\n      cursor: pointer;\n      font-weight: bold;\n      transition: background 0.3s;\n    }\n    button:hover {\n      background: #2980b9;\n    }\n    button:disabled {\n      background: #bdc3c7;\n    }\n    .loading {\n      text-align: center;\n      display: none;\n      margin-top: 10px;\n    }\n    .loading-dots:after {\n      content: \'.\';\n      animation: dots 1s steps(5, end) infinite;\n    }\n    @keyframes dots {\n      0%, 20% { content: \'.\'; }\n      40% { content: \'..\'; }\n      60% { content: \'...\'; }\n      80%, 100% { content: \'\'; }\n    }\n  </style>\n</head>\n<body>\n  <div class="header">\n    <h2>SRT Fact-Check AI</h2>\n  </div>\n\n  <div id="detected-text" class="content-box">\n    Detecting content...\n  </div>\n\n  <button id="check-btn" disabled>Fact Check Claim</button>\n\n  <div id="loading" class="loading">\n    Analyzing claim<span class="loading-dots"></span>\n  </div>\n\n  <div id="result"></div>\n\n  <script src="popup.js"></script>\n</body>\n</html>\n')
    with open("extension/content.js", "w") as f: f.write('// content.js\n// Listen for requests from the popup\nchrome.runtime.onMessage.addListener((request, sender, sendResponse) => {\n    if (request.action === "extractText") {\n        const text = extractSrtContent();\n        sendResponse({ text: text });\n    }\n    return true;\n});\n\nfunction extractSrtContent() {\n    let combinedText = "";\n\n    // 1. Target "Content In Review" section\n    const allDivs = Array.from(document.querySelectorAll(\'div\'));\n    const contentHeader = allDivs.find(el => el.innerText.trim() === "Content In Review");\n\n    if (contentHeader) {\n        // Find the next sibling or parent\'s child that contains the text\n        const nextEl = contentHeader.nextElementSibling;\n        if (nextEl) {\n            combinedText += "--- CONTENT IN REVIEW ---\\n" + nextEl.innerText.trim() + "\\n\\n";\n        }\n    }\n\n    // 2. Target "Transcript" section\n    const transcriptHeader = allDivs.find(el => el.innerText.trim() === "Transcript");\n    if (transcriptHeader) {\n        const nextEl = transcriptHeader.nextElementSibling;\n        if (nextEl) {\n            combinedText += "--- TRANSCRIPT ---\\n" + nextEl.innerText.trim() + "\\n\\n";\n        }\n    }\n\n    if (combinedText) return combinedText.trim();\n\n    // Fallback: Try common selectors or selection\n    const selectors = [\n        \'[data-testid="post_message"]\',\n        \'article div[dir="auto"]\',\n        \'textarea\'\n    ];\n\n    for (const selector of selectors) {\n        const element = document.querySelector(selector);\n        if (element && element.innerText.trim()) {\n            return element.innerText.trim();\n        }\n    }\n\n    // Fallback: get selected text\n    return window.getSelection().toString().trim() || "No text detected. Please select the text you want to fact-check.";\n}\n')
    with open("extension/background.js", "w") as f: f.write('// background.js\n// Handles messaging or periodic tasks if needed\nchrome.runtime.onInstalled.addListener(() => {\n    console.log("SRT Fact-Check AI Extension installed.");\n});\n')
    with open("extension/icons/icon16.png", "wb") as f: f.write(base64.b64decode(""))
    with open("extension/icons/icon48.png", "wb") as f: f.write(base64.b64decode(""))
    with open("extension/icons/icon128.png", "wb") as f: f.write(base64.b64decode(""))
    print("Extension folder reconstructed successfully!")

if __name__ == "__main__":
    reconstruct()